import { mkdir, writeFile } from "node:fs/promises";
import test from "node:test";
import { join } from "node:path";

import queueRunner from "../../.pi/agent/extensions/queue-runner.ts";
import recoveryRuntime from "../../.pi/agent/extensions/recovery-runtime.ts";
import safeBash from "../../.pi/agent/extensions/safe-bash.ts";
import tillDone from "../../.pi/agent/extensions/till-done.ts";
import { FakePi, copyFixtureRepoFile, makeCtx, makeTempRepo, readAuditLog } from "../extension-units/test-utils.ts";

async function setupIntegrationRepo(branch = "feat/harness-038-tests") {
  const cwd = await makeTempRepo("core-workflows-");
  await mkdir(join(cwd, "logs"), { recursive: true });

  for (const relativePath of [
    ".pi/agent/models.json",
    ".pi/agent/teams/activation-policy.json",
    ".pi/agent/teams/planning.yaml",
    ".pi/agent/teams/build.yaml",
    ".pi/agent/teams/quality.yaml",
    ".pi/agent/teams/recovery.yaml",
    ".pi/agent/packets/packet-policy.json",
    ".pi/agent/handoffs/handoff-policy.json",
    ".pi/agent/validation/completion-gate-policy.json",
    ".pi/agent/recovery/recovery-policy.json",
  ]) {
    await copyFixtureRepoFile(cwd, relativePath);
  }

  await writeFile(
    join(cwd, ".pi", "agent", "state", "runtime", "queue.json"),
    `${JSON.stringify({ version: 1, paused: false, activeJobId: null, jobs: [] }, null, 2)}\n`,
  );

  const pi = new FakePi(branch);
  tillDone(pi as any);
  queueRunner(pi as any);
  recoveryRuntime(pi as any);
  safeBash(pi as any);

  const tool = (name: string) => pi.getTool(name);
  const ctx = (options: { hasUI?: boolean; confirmResult?: boolean } = {}) => makeCtx(cwd, options);

  return {
    cwd,
    pi,
    ctx,
    taskUpdate: (params: Record<string, unknown>) => tool("task_update").execute("tool-call-id", params, undefined, undefined, ctx()),
    runNextQueueJob: (params: Record<string, unknown> = {}) => tool("run_next_queue_job").execute("tool-call-id", params, undefined, undefined, ctx()),
    inspectQueueState: (params: Record<string, unknown> = {}) => tool("inspect_queue_state").execute("tool-call-id", params, undefined, undefined, ctx()),
    resolveRecoveryRuntimeDecision: (params: Record<string, unknown>) => tool("resolve_recovery_runtime_decision").execute("tool-call-id", params, undefined, undefined, ctx()),
    onToolCall: () => pi.getHandler("tool_call"),
  };
}

async function readTaskState(cwd: string) {
  const raw = await import("node:fs/promises").then((fs) => fs.readFile(join(cwd, ".pi", "agent", "state", "runtime", "tasks.json"), "utf8"));
  return JSON.parse(raw) as {
    activeTaskId: string | null;
    tasks: Array<{ id: string; status: string; taskClass: string; validation?: { decision?: string | null } | null; notes?: string[] }>;
  };
}

async function writeQueue(cwd: string, queue: unknown) {
  await writeFile(join(cwd, ".pi", "agent", "state", "runtime", "queue.json"), `${JSON.stringify(queue, null, 2)}\n`);
}

test("core workflow: docs-only task can complete through lighter review-backed validation", async () => {
  const { cwd, taskUpdate } = await setupIntegrationRepo();

  const created = await taskUpdate({
    action: "create",
    title: "Document the operator workflow",
    taskClass: "docs",
    acceptance: ["Document the bounded operator workflow"],
  });
  const taskId = (created as any).details.task.id as string;

  await taskUpdate({ action: "claim", id: taskId, owner: "assistant" });
  await taskUpdate({ action: "start", id: taskId });
  await taskUpdate({ action: "evidence", id: taskId, evidence: ["Changed files: .pi/agent/docs/operator_workflow.md"] });
  await taskUpdate({ action: "review", id: taskId });
  await taskUpdate({
    action: "validate",
    id: taskId,
    validationSource: "review",
    validationDecision: "pass",
    validationChecklist: {
      acceptance: "met",
      tests: "not_applicable",
      diff_review: "not_applicable",
      evidence: "met",
    },
  });
  await taskUpdate({ action: "done", id: taskId });

  const state = await readTaskState(cwd);
  assert.equal(state.tasks.find((task) => task.id === taskId)?.status, "done");
});

test("core workflow: implementation pass can run through queue start, validation pass, and queue finalization", async () => {
  const { cwd, runNextQueueJob, taskUpdate, inspectQueueState } = await setupIntegrationRepo();

  await writeQueue(cwd, {
    version: 1,
    paused: false,
    activeJobId: null,
    jobs: [
      {
        id: "job-impl-pass",
        goal: "Implement a bounded runtime fix",
        priority: "high",
        status: "queued",
        team: "build",
        assignedRole: "backend_worker",
        workType: "implementation",
        domains: ["backend"],
        allowedPaths: [".pi/agent/extensions/queue-runner.ts"],
        acceptanceCriteria: ["Implementation workflow reaches done and finalizes the queue job"],
      },
    ],
  });

  const start = await runNextQueueJob({ owner: "assistant", allowInitialHandoff: true });
  const taskId = (start as any).details.startedJob.linkedTaskId as string;

  await taskUpdate({ action: "evidence", id: taskId, evidence: ["Changed files: .pi/agent/extensions/queue-runner.ts"] });
  await taskUpdate({ action: "review", id: taskId });
  await taskUpdate({
    action: "validate",
    id: taskId,
    validationSource: "validator",
    validationDecision: "pass",
    validationChecklist: {
      acceptance: "met",
      tests: "met",
      diff_review: "met",
      evidence: "met",
    },
  });
  await taskUpdate({ action: "done", id: taskId });

  const finalize = await runNextQueueJob({ owner: "assistant" });
  const inspection = await inspectQueueState({ recentLimit: 5 });

  assert.equal((finalize as any).details.action, "finalized");
  assert.equal((inspection as any).details.summary.jobCounts.done, 1);
  assert.equal((inspection as any).details.summary.activeJobId, null);
});

