test("core workflow: recovery path finalizes a failed queue job with a bounded recovery recommendation", async () => {
  const { cwd, runNextQueueJob, taskUpdate } = await setupIntegrationRepo();

  await writeQueue(cwd, {
    version: 1,
    paused: false,
    activeJobId: null,
    jobs: [
      {
        id: "job-recovery",
        goal: "Exercise recovery after failed validation",
        priority: "high",
        status: "queued",
        team: "build",
        assignedRole: "backend_worker",
        workType: "implementation",
        domains: ["backend"],
        allowedPaths: [".pi/agent/extensions/queue-runner.ts"],
        acceptanceCriteria: ["Failed implementation produces a bounded recovery recommendation"],
      },
    ],
  });

  const start = await runNextQueueJob({ owner: "assistant" });
  const taskId = (start as any).details.startedJob.linkedTaskId as string;

  await taskUpdate({ action: "evidence", id: taskId, evidence: ["Changed files: src/recovery.ts"] });
  await taskUpdate({ action: "review", id: taskId });
  await taskUpdate({
    action: "validate",
    id: taskId,
    validationSource: "validator",
    validationDecision: "fail",
    validationChecklist: {
      acceptance: "met",
      tests: "not_met",
      diff_review: "met",
      evidence: "met",
    },
    note: "validation failed and recovery should be invoked",
  });

  const finalize = await runNextQueueJob({ owner: "assistant" });
  const details = (finalize as any).details;

  assert.equal(details.action, "finalized");
  assert.equal(details.finalizedJob.status, "failed");
  assert.ok(details.recoveryDecision);
  assert.equal(details.recoveryDecision.recommendedAction, "retry_same_lane");
});

test("core workflow: provider/tool block surfaces both safe-bash blocking and provider recovery guidance", async () => {
  const { cwd, onToolCall, resolveRecoveryRuntimeDecision } = await setupIntegrationRepo("main");

  const toolResult = await onToolCall()({ toolName: "write", input: { path: ".env" } }, makeCtx(cwd));
  assert.deepEqual(toolResult, {
    block: true,
    reason: "Blocked write: secret/env files are protected",
  });

  const audit = await readAuditLog(cwd);
  assert.match(audit, /"action":"blocked"/);
  assert.match(audit, /secret\/env files are protected/);

  const recoveryResult = await resolveRecoveryRuntimeDecision({
    role: "backend_worker",
    currentModelId: "openai-codex/gpt-5.4",
    providerFailureState: "model_unavailable",
    toolState: "unavailable",
  });

  const decision = (recoveryResult as any).details.decision;
  assert.equal(decision.haltAutonomy, true);
  assert.equal(decision.recommendedAction, "switch_provider");
});
