  await writeQueue(cwd, { version: 1, paused: false, activeJobId: null, jobs: [{ id: "job-impl-pass", goal: "Implement a bounded runtime fix", priority: "high", status: "queued", team: "build", assignedRole: "backend_worker", workType: "implementation", domains: ["backend"], allowedPaths: [".pi/agent/extensions/queue-runner.ts"], acceptanceCriteria: ["Implementation workflow reaches done and finalizes the queue job"] }] });
