  await taskUpdate({ action: "evidence", id: taskId, evidence: ["Changed files: .pi/agent/extensions/queue-runner.ts"] });
  await taskUpdate({ action: "review", id: taskId });
  await taskUpdate({ action: "validate", id: taskId, validationSource: "validator", validationDecision: "pass", validationChecklist: { acceptance: "met", tests: "met", diff_review: "met", evidence: "met" } });
